using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;
using OpenAI;
using ResearchAgent;

var builder = Host.CreateApplicationBuilder(args);

// Register HttpClient for web search
builder.Services.AddHttpClient<WebSearchTool>(client =>
{
    client.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
    client.Timeout = TimeSpan.FromSeconds(15);
});

builder.Services.AddSingleton<NoteTool>();

// Register the chat client via MEAI abstraction.
// Configure via environment variable: OPENAI_API_KEY
var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable or AI:ApiKey in config.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddSingleton<IChatClient>(sp =>
    new OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient());

builder.Services.AddHostedService<ResearchHostedService>();

var host = builder.Build();
await host.RunAsync();

/// <summary>
/// Hosted service that runs the research agent loop.
/// </summary>
sealed class ResearchHostedService(
    IChatClient chatClient,
    WebSearchTool webSearchTool,
    NoteTool noteTool,
    IHostApplicationLifetime lifetime) : BackgroundService
{
    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        Console.WriteLine("╔══════════════════════════════════════╗");
        Console.WriteLine("║       AI Research Agent (v1.0)       ║");
        Console.WriteLine("╚══════════════════════════════════════╝");
        Console.WriteLine();

        // Build tool list from instance methods decorated with [Description]
        var tools = new List<AITool>();
        foreach (var method in typeof(WebSearchTool).GetMethods(
            System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance | System.Reflection.BindingFlags.DeclaredOnly))
        {
            tools.Add(AIFunctionFactory.Create(method, webSearchTool));
        }
        foreach (var method in typeof(NoteTool).GetMethods(
            System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance | System.Reflection.BindingFlags.DeclaredOnly))
        {
            if (method.GetCustomAttributes(typeof(System.ComponentModel.DescriptionAttribute), false).Length > 0)
                tools.Add(AIFunctionFactory.Create(method, webSearchTool: null!, target: noteTool));
        }

        var instructions = """
            You are a thorough research assistant. Your goal is to research the topic provided by the user
            and produce a well-organized summary of your findings.

            Follow this process:
            1. Search the web for the topic using multiple relevant queries (at least 2-3 different angles).
            2. Fetch promising pages to get detailed information.
            3. Save key findings as notes using the note-taking tool, including the source.
            4. After gathering enough information, retrieve all your notes.
            5. Write a comprehensive summary with sections, key points, and source citations.

            Be thorough but concise. Cite your sources.
            """;

        // Create the agent with tools
        var agent = new ChatClientAgent(
            chatClient,
            name: "ResearchAgent",
            description: "An AI research assistant that searches the web and takes notes.",
            instructions: instructions,
            tools: tools);

        Console.Write("Enter a research topic: ");
        var topic = Console.ReadLine()?.Trim();
        if (string.IsNullOrWhiteSpace(topic))
        {
            Console.WriteLine("No topic provided. Exiting.");
            lifetime.StopApplication();
            return;
        }

        Console.WriteLine($"\nResearching: {topic}");
        Console.WriteLine("Working...\n");

        try
        {
            // Create a session and run the agent
            var session = await agent.CreateSessionAsync(stoppingToken);

            var runOptions = new ChatClientAgentRunOptions
            {
                ChatOptions = new ChatOptions
                {
                    Temperature = 0f,
                    MaxOutputTokens = 4096,
                },
            };

            var userMessage = new ChatMessage(
                ChatRole.User,
                $"Please research the following topic and provide a comprehensive summary: {topic}");

            await foreach (var update in agent.RunStreamingAsync(userMessage, session, runOptions, stoppingToken))
            {
                if (!string.IsNullOrEmpty(update.Text))
                {
                    Console.Write(update.Text);
                }
            }

            Console.WriteLine("\n");

            // Display collected notes summary
            if (noteTool.Notes.Count > 0)
            {
                Console.WriteLine($"--- Research Notes ({noteTool.Notes.Count} collected) ---");
                foreach (var note in noteTool.Notes)
                {
                    Console.WriteLine($"  • {note.Title} (Source: {note.Source})");
                }
                Console.WriteLine();
            }
        }
