 using System.ComponentModel;
 using System.Net.Http.Json;
 using System.Text.Json;

 namespace ResearchAgent;

 /// <summary>
 /// Provides a web search tool that the agent can invoke to find information.
 /// Uses a simple HTTP-based search approach via DuckDuckGo Instant Answer API.
 /// </summary>
 public sealed class WebSearchTool
 {
     private readonly HttpClient _httpClient;

     public WebSearchTool(HttpClient httpClient)
     {
         _httpClient = httpClient;
     }

     [Description("Search the web for information on a given query. Returns a list of relevant results with titles and snippets.")]
     public async Task<string> SearchWebAsync(
         [Description("The search query to look up")] string query,
         CancellationToken cancellationToken = default)
     {
         try
         {
             var encoded = Uri.EscapeDataString(query);
             var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
             var response = await _httpClient.GetAsync(url, cancellationToken);
             response.EnsureSuccessStatusCode();

             var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
             var results = new List<string>();

             // Extract the abstract (main result)
             var abstractText = json.GetProperty("Abstract").GetString();
             var abstractSource = json.GetProperty("AbstractSource").GetString();
             if (!string.IsNullOrWhiteSpace(abstractText))
             {
                 results.Add($"[{abstractSource}] {abstractText}");
             }

             // Extract related topics
             if (json.TryGetProperty("RelatedTopics", out var topics))
             {
                 foreach (var topic in topics.EnumerateArray().Take(5))
                 {
                     if (topic.TryGetProperty("Text", out var text) &&
                         !string.IsNullOrWhiteSpace(text.GetString()))
                     {
                         var firstUrl = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : "";
                         results.Add($"[{firstUrl}] {text.GetString()}");
                     }
                 }
             }

             if (results.Count == 0)
             {
                 return $"No detailed results found for '{query}'. Try a more specific or different query.";
             }

             return string.Join("\n\n", results);
         }
         catch (Exception ex)
         {
             return $"Search failed for '{query}': {ex.Message}. Try a different query.";
         }
     }

     [Description("Fetch the content of a specific web page URL and return its text. Useful for reading articles found via search.")]
     public async Task<string> FetchPageAsync(
         [Description("The full URL of the web page to fetch")] string url,
         CancellationToken cancellationToken = default)
     {
         try
         {
             var response = await _httpClient.GetAsync(url, cancellationToken);
             response.EnsureSuccessStatusCode();

             var html = await response.Content.ReadAsStringAsync(cancellationToken);

             // Basic HTML-to-text: strip tags and decode common entities
             var text = System.Text.RegularExpressions.Regex.Replace(html, "<script[^>]*>[\\s\\S]*?</script>", " ");
             text = System.Text.RegularExpressions.Regex.Replace(text, "<style[^>]*>[\\s\\S]*?</style>", " ");
             text = System.Text.RegularExpressions.Regex.Replace(text, "<[^>]+>", " ");
             text = System.Net.WebUtility.HtmlDecode(text);
             text = System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ").Trim();

             // Truncate to avoid blowing up context windows
             const int maxLength = 4000;
             if (text.Length > maxLength)
             {
                 text = text[..maxLength] + "... [truncated]";
             }

             return text;
         }
         catch (Exception ex)
         {
             return $"Failed to fetch '{url}': {ex.Message}";
         }
     }
 }

